import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

interface DataRequest {
    _id: string;
    userWallet: string;
    docType: string;
    status: string;
    sharedHash?: string;
    sharedIpfs?: string;
    requestedAt: string;
}

const EntityDashboard: React.FC = () => {
    const { user, token } = useAuth();
    const [userWallet, setUserWallet] = useState('');
    const [docType, setDocType] = useState('Aadhar Card');
    const [requests, setRequests] = useState<DataRequest[]>([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchMyRequests();
    }, []);

    const fetchMyRequests = async () => {
        try {
            const res = await fetch('http://localhost:5000/api/entity/my-requests', {
                headers: { 'x-auth-token': token || '' }
            });
            const data = await res.json();
            if (res.ok) setRequests(data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleCreateRequest = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');

        try {
            const res = await fetch('http://localhost:5000/api/entity/request', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-auth-token': token || ''
                },
                body: JSON.stringify({ userWallet, docType })
            });

            if (res.ok) {
                setMessage('Request sent successfully!');
                setUserWallet('');
                fetchMyRequests();
            } else {
                const data = await res.json();
                setMessage(`Error: ${data.message}`);
            }
        } catch (err) {
            setMessage('Failed to send request');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fade-in" style={{ maxWidth: '1200px', margin: '0 auto' }}>
            <div style={{ marginBottom: '4rem' }}>
                <h1 style={{ fontSize: '3rem' }}>Institution Portal</h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1.2rem' }}>
                    Authenticated as: <strong style={{ color: '#fff' }}>{user?.entityName || user?.username}</strong>
                </p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '2.5rem' }}>
                {/* Request Form */}
                <div className="glass" style={{ padding: '2.5rem', height: 'fit-content' }}>
                    <h3 style={{ marginBottom: '1.5rem' }}>New Data Request</h3>

                    {!user?.walletAddress && (
                        <div className="status-badge" style={{ background: 'rgba(255,165,0,0.1)', color: 'orange', border: '1px solid orange', marginBottom: '1.5rem', width: '100%', justifyContent: 'center' }}>
                            Action Required: Link your wallet in the Hub
                        </div>
                    )}

                    <form onSubmit={handleCreateRequest} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', opacity: user?.walletAddress ? 1 : 0.5, pointerEvents: user?.walletAddress ? 'all' : 'none' }}>
                        <div>
                            <label>User Wallet Address</label>
                            <input 
                                type="text" 
                                placeholder="0x..." 
                                value={userWallet}
                                onChange={(e) => setUserWallet(e.target.value)}
                                required
                            />
                        </div>
                        <div>
                            <label>Required Document</label>
                            <select 
                                value={docType}
                                onChange={(e) => setDocType(e.target.value)}
                                style={{ 
                                    width: '100%', 
                                    padding: '1rem', 
                                    background: 'rgba(255,255,255,0.05)', 
                                    border: '1px solid var(--card-border)',
                                    color: '#fff'
                                }}
                            >
                                <option value="Aadhar Card">Aadhar Card</option>
                                <option value="PAN Card">PAN Card</option>
                                <option value="Passport">Passport</option>
                                <option value="Driving License">Driving License</option>
                            </select>
                        </div>
                        <button type="submit" className="btn btn-primary" disabled={loading || !user?.walletAddress}>
                            {loading ? 'Sending...' : 'Request Verification'}
                        </button>
                    </form>
                    {message && (
                        <div style={{ 
                            marginTop: '1.5rem', 
                            padding: '1rem', 
                            borderRadius: '8px',
                            background: message.includes('Error') ? 'rgba(255,68,68,0.1)' : 'rgba(0,255,136,0.1)',
                            color: message.includes('Error') ? 'var(--error)' : 'var(--success)',
                            fontSize: '0.9rem',
                            textAlign: 'center',
                            border: `1px solid ${message.includes('Error') ? 'var(--error)' : 'var(--success)'}`
                        }}>
                            {message}
                        </div>
                    )}
                </div>

                {/* Requests List */}
                <div className="glass" style={{ padding: '2.5rem' }}>
                    <h3 style={{ marginBottom: '1.5rem' }}>Pending & Verified Audits</h3>
                    {requests.length === 0 ? (
                        <div style={{ textAlign: 'center', opacity: 0.5, marginTop: '4rem' }}>
                            <p>You haven't initiated any requests yet.</p>
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {requests.map((req) => (
                                <div key={req._id} className="glass" style={{ padding: '1.5rem', background: 'rgba(255,255,255,0.02)' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                        <div style={{ fontFamily: 'monospace', fontSize: '0.9rem' }}>
                                            {req.userWallet}
                                        </div>
                                        <div className={`status-badge ${req.status === 'approved' ? 'status-verified' : ''}`} style={{ fontSize: '0.8rem' }}>
                                            {req.status.toUpperCase()}
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                                        <div>
                                            <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Document Type</div>
                                            <div style={{ fontSize: '1.1rem', fontWeight: 600 }}>{req.docType}</div>
                                        </div>
                                        <div style={{ fontSize: '0.7rem', opacity: 0.5 }}>
                                            Requested: {new Date(req.requestedAt).toLocaleDateString()}
                                        </div>
                                    </div>

                                    {req.status === 'approved' && (
                                        <div style={{ marginTop: '1.5rem', padding: '1rem', background: 'rgba(0,0,0,0.3)', borderRadius: '8px' }}>
                                            <div style={{ marginBottom: '0.5rem' }}>
                                                <label style={{ fontSize: '0.7rem', opacity: 0.6 }}>On-Chain Hash Proof</label>
                                                <div style={{ fontFamily: 'monospace', fontSize: '0.8rem', wordBreak: 'break-all', color: 'var(--success)' }}>
                                                    {req.sharedHash}
                                                </div>
                                            </div>
                                            <div>
                                                <label style={{ fontSize: '0.7rem', opacity: 0.6 }}>IPFS CID</label>
                                                <div style={{ fontFamily: 'monospace', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                                                    {req.sharedIpfs}
                                                </div>
                                                <a href={`https://gateway.pinata.cloud/ipfs/${req.sharedIpfs}`} target="_blank" rel="noreferrer" style={{ fontSize: '0.7rem', color: '#fff', textDecoration: 'underline' }}>
                                                    View Source Document
                                                </a>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default EntityDashboard;
